arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // EF Core 9 Cosmos: HasIndex now throws; manage indexing via Azure Portal/Bicep.
    // Preserve the legacy "Discriminator" property name (EF9 defaults to "$type").
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");
    // Preserve the legacy "Blog|1" id format (EF9 defaults to key-only ids).
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
}

